def max_sum_window_of_size_k(nums, k):
    if k > len(nums) or k <= 0:
        return 0
    cur = sum(nums[:k])
    best = cur
    for i in range(k, len(nums)):
        cur += nums[i] - nums[i - k]
        if cur > best:
            best = cur
    return best

